SHARED VARIABLES:
  flag[0] : boolean = false
  flag[1] : boolean = false
  turn : integer = 0

PROCESS P(i) where i = 0 or 1, j = 1 - i:

do {
  // ENTRY SECTION
  flag[i] := true
  turn := j
  while (flag[j] = true and turn = j) do
    // busy wait - process waits
  end while

  // CRITICAL SECTION
  // ... access shared resource ...

  // EXIT SECTION
  flag[i] := false

  // REMAINDER SECTION
  // ... rest of the code ...

} while (true)

#include <stdio.h>
#include <stdbool.h>
#include <pthread.h>

#define NUM_ITERATIONS 5

bool flag[2] = {false, false};
int turn = 0;

void* process(void* arg) {
    int id = *(int*)arg;
    int other = 1 - id;

    for (int i = 0; i < NUM_ITERATIONS; i++) {
        // Entry Section
        flag[id] = true;
        turn = other;
        while (flag[other] && turn == other);

        // Critical Section
        printf("Process %d is in CS (iteration %d)\n", id, i+1);

        // Exit Section
        flag[id] = false;

        // Remainder Section
    }
    return NULL;
}

int main() {
    pthread_t p0, p1;
    int id0 = 0, id1 = 1;

    pthread_create(&p0, NULL, process, &id0);
    pthread_create(&p1, NULL, process, &id1);

    pthread_join(p0, NULL);
    pthread_join(p1, NULL);

    return 0;
}

public class PetersonSolution implements Runnable {
    private static volatile boolean[] flag = {false, false};
    private static volatile int turn = 0;
    private static final int ITERATIONS = 5;
    private final int processId;

    public PetersonSolution(int processId) {
        this.processId = processId;
    }

    public void run() {
        int other = 1 - processId;
        for (int i = 0; i < ITERATIONS; i++) {
            // Entry Section
            flag[processId] = true;
            turn = other;
            while (flag[other] && turn == other) {
                // Busy wait - spinlock
            }

            // Critical Section
            System.out.println("Process " + processId + " is in CS (iteration " + (i+1) + ")");

            // Exit Section
            flag[processId] = false;

            // Remainder Section
        }
    }

    public static void main(String[] args) throws InterruptedException {
        Thread t0 = new Thread(new PetersonSolution(0));
        Thread t1 = new Thread(new PetersonSolution(1));

        t0.start();
        t1.start();

        t0.join();
        t1.join();

        System.out.println("Both processes completed");
    }
}
